<template>
  <div class="login-container">
    <h1 class="platform-title">校园二手交易平台</h1>
    <div class="login-form">
      <h2>选择登录身份</h2>
      <div class="form-group">
        <select v-model="userType" required>
          <option value="0">普通用户</option>
          <option value="1">管理员</option>
        </select>
      </div>
      <form @submit.prevent="login">
        <div class="form-group">
          <input type="text" v-model="username" placeholder="用户名" required>
        </div>
        <div class="form-group">
          <input type="password" v-model="password" placeholder="密码" required>
        </div>
        <button type="submit">登录</button>
        <div class="form-links">
          <a @click="forgotPassword">忘记密码</a> |
          <a @click="goToRegister">还没有账户？去注册</a>
        </div>
      </form>
    </div>
  </div>
</template>

<script>
import axios from 'axios';

export default {
  data() {
    return {
      username: '', 
      password: '',
      userType: '0', 
    };
  },
  methods: {
    async login() {
      let loginUrl = '';
      if (this.userType === '0') {
        loginUrl = 'http://localhost:8080/api/login';
      } else if (this.userType === '1') {
        loginUrl = 'http://localhost:8080/api/admin/login'; // 确保与后端端点路径一致
      }
      try {
        const response = await axios.post(loginUrl, {
          username: this.username,
          password: this.password,
        }, {
          headers: {
            'Content-Type': 'application/json'
          }
        });

        // 检查响应内容
        if (response.data.token && response.data.userId && response.data.username) {
          // 存储token和userId
          localStorage.setItem('token', response.data.token);
          localStorage.setItem('userId', response.data.userId);
          localStorage.setItem('username', response.data.username);

          // 检查函数
          this.checkStoredUserId();

          if (this.userType === '0') {
            this.$router.push({ name: 'MainPage' });
          } else if (this.userType === '1') {
            this.$router.push({ name: 'AdminPage' });
          }
        } else {
          throw new Error('No token received');
        }
      } catch (error) {
        console.error('登录失败:', error);
        if (error.response) {
          alert(`登录失败：${error.response.data.message || '用户名或密码错误！'}`);
        } else if (error.request) {
          alert('登录失败，服务器未响应。');
        } else {
          alert(error.message);
        }
      }
    },
    checkStoredUserId() {
      const storedUserId = localStorage.getItem('userId');
      if (storedUserId) {
        console.log('userId存储正确:', storedUserId);
      } else {
        console.error('userId未存储或存储错误');
      }
    },
    
    goToRegister() {
      // 跳转到注册页面
      this.$router.push({ name: 'RegisterUser' });
    },
    forgotPassword() {
      // 忘记密码的逻辑
      alert('请联系管理员王先生找回密码，联系电话为13363399256');
    }
  }
};
</script>


<style>
  body {
    font-family: Arial, sans-serif;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    height: 100vh;
    margin: 0;
  }
  .platform-title {
    margin-bottom: 20px;
  }
  .login-container {
    width: 100%;
    max-width: 360px;
    padding: 20px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
    background: #fff;
    text-align: center;
  }
  .login-form {
    text-align: center;
  }
  .form-group {
    margin-bottom: 15px;
  }
  input {
    width: 100%;
    padding: 10px;
    box-sizing: border-box;
  }
  button {
    width: 100%;
    padding: 10px;
    background-color: #007bff;
    color: white;
    border: none;
    cursor: pointer;
  }
  button:hover {
    background-color: #0056b3;
  }
  .form-links {
    margin-top: 10px;
  }
  .form-links a {
    cursor: pointer;
    color: blue;
    text-align: center;
  }
  .form-links a:hover {
    text-decoration: underline;
  }
</style>
