<template>
  <div class="register-container">
    <h2>注册</h2>
    <form @submit.prevent="register">
      <div class="form-group">
        <select v-model="userType" required>
          <option value="0">普通用户</option>
          <option value="1">管理员</option>
        </select>
      </div>
      <div class="form-group">
        <input type="text" v-model="username" placeholder="用户名" required>
      </div>
      <div class="form-group">
        <input type="text" v-model="studentId" placeholder="学号" required pattern="\d{10}" title="学号应为10位数字">
      </div>
      <div class="form-group">
        <input type="tel" v-model="phone" placeholder="手机号" required pattern="\d{11}" title="手机号应为11位数字">
      </div>
      <div class="form-group">
        <input type="password" v-model="password" placeholder="密码" required pattern=".{6,20}" title="密码应为6到20位">
      </div>
      <div class="form-group">
        <input type="password" v-model="confirmPassword" placeholder="确认密码" required pattern=".{6,20}" title="密码应为6到20位">
      </div>
      <button type="button" @click="goToLogin" style="margin-bottom: 10px;">返回登录</button>
      <button type="submit">注册</button>
    </form>
  </div>
</template>

<script>
import axios from 'axios';

export default {
  name: 'RegisterUser',
  data() {
    return {
      username: '',
      studentId: '', 
      phone: '',
      password: '',
      confirmPassword: '',
      userType: '0',// 默认为普通用户
      userCount: 200
    };
  },
  methods: {
    goToLogin() {
      this.$router.push({ name: 'LoginUser' });
    },
    async register() {
      // 检查密码和确认密码是否一致
      if (this.password !== this.confirmPassword) {
        alert('密码和确认密码不一致！');
        return;
      }

      // 构建请求体
      const userData = {
        username: this.username,
        studentId: this.studentId, // 使用正确的变量名，与后端实体类中的字段名一致
        phone: this.phone, // 使用正确的变量名，与后端实体类中的字段名一致
        password: this.password,
        userType: this.userType // 添加用户类型到请求体
      };

      try {
        // 发送注册请求到后端
        const response = await axios.post('http://localhost:8080/api/register', userData, {
          headers: {
            'Content-Type': 'application/json'
          }
        });

        // 检查响应状态
        if (response.status === 200) {
          // 直接使用响应的body作为消息，因为后端返回的是字符串
          alert('注册成功！');
          this.userCount = localStorage.getItem('userCount');
          this.userCount++; // 增加用户数量 
          localStorage.setItem('userCount', this.userCount.toString()); 
          console.log(this.userCount);
          // 假设有一个名为 'LoginUser' 的路由用于登录
          this.$router.push({ name: 'LoginUser' });
        } else {
          // 处理非200状态码的情况
          alert('注册失败！状态码：' + response.status);
        }
      } catch (error) {
        console.error('注册请求失败：', error);
        // 当捕获到错误时，尝试从错误响应中获取错误信息
        if (error.response) {
          // 服务器返回的错误状态码和消息
          alert('注册失败！用户名已存在！');
        } else {
          // 请求未发出或网络问题
          alert('注册请求失败，请稍后再试。');
        }
      }
    }
  }
}
</script>


<style>
  body {
    font-family: Arial, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
    margin: 0;
  }
  .register-container {
    width: 100%;
    max-width: 360px;
    padding: 20px;
    box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
    background: #fff;
    text-align: center;
  }
  .form-group {
    margin-bottom: 15px;
  }
  input {
    width: 100%;
    padding: 10px;
    box-sizing: border-box;
  }
  button {
    width: 100%;
    padding: 10px;
    background-color: #007bff;
    color: white;
    border: none;
    cursor: pointer;
  }
  button:hover {
    background-color: #0056b3;
  }
  a {
    cursor: pointer;
    color: blue;
    text-align: center;
  }
  a:hover {
    text-decoration: underline;
  }
</style>
