<template>
  <div class="main-page">
    <el-container style="height: 100vh;">
      <!-- 添加一个头部导航栏 -->
      <el-header class="header-nav">
        <div class="nav-content">
          <span class="title">校园二手交易平台</span>
        </div>
      </el-header>
      <el-aside class="fixed-aside" width="200px">
        <el-menu default-active="0" class="el-menu-vertical-demo">
          <el-menu-item index="0" @click="activeTab = 'mainPage'">
            <i class="el-icon-main"></i>
            <template #title>首页</template>
          </el-menu-item>
          <el-menu-item index="1" @click="activeTab = 'editProfile'">
            <i class="el-icon-user"></i>
            <template #title>修改个人信息</template>
          </el-menu-item>
          <el-menu-item index="2" @click="activeTab = 'changePassword'">
            <i class="el-icon-lock"></i>
            <template #title>修改密码</template>
          </el-menu-item>
          <el-menu-item index="3" @click="activeTab = 'productList'">
            <i class="el-icon-s-goods"></i>
            <template #title>商品列表</template>
          </el-menu-item>
          <el-menu-item index="4" @click="activeTab = 'userList'">
            <i class="el-icon-userList"></i>
            <template #title>用户列表</template>
          </el-menu-item>
          <el-menu-item index="5" @click="activeTab = 'dataStatistics'">
            <i class="el-icon-data"></i>
            <template #title>数据统计</template>
          </el-menu-item>
          <el-menu-item index="6" @click="logout">
            <i class="el-icon-switch-button"></i>
            <template #title>退出登录</template>
          </el-menu-item>
        </el-menu>
      </el-aside>
      <el-main class="main-content" style="padding-right: 250px;">
        <!-- 首页 -->
        <div v-if="activeTab === 'mainPage'" class="main-page-content">
          <h1>欢迎来到首页</h1>
          <div class="carousel-container">
            <CarouselSlider />
          </div>
        </div>
        <!-- 修改个人信息 -->
        <div v-if="activeTab === 'editProfile'" class="edit-profile">
          <el-form :model="userProfile" label-width="100px"> 
            <el-form-item label="用户名">
              <el-input v-model="userProfile.username" size="large"></el-input>
            </el-form-item>
            <el-form-item label="学号">
              <el-input v-model="userProfile.studentId" size="large"></el-input>
            </el-form-item>
            <el-form-item label="手机号">
              <el-input v-model="userProfile.phone" size="large"></el-input>
            </el-form-item>
            <el-form-item label="学院">
              <el-input v-model="userProfile.college" size="large"></el-input>
            </el-form-item>
            <el-form-item label="专业">
              <el-input v-model="userProfile.major" size="large"></el-input>
            </el-form-item>
            <el-form-item>
              <el-button type="primary" @click="updateUserProfile" size="large">保存</el-button>
            </el-form-item>
          </el-form>
        </div>
        <!-- 修改密码 -->
        <div v-if="activeTab === 'changePassword'" class="change-password">
          <el-form :model="passwords" ref="passwordForm" @submit.prevent="changePassword" label-width="100px">
            <el-form-item label="旧密码" prop="oldPassword" :rules="[{ required: true, message: '请输入旧密码', trigger: 'blur' }]">
              <el-input type="password" v-model="passwords.oldPassword" size="large" autocomplete="off"></el-input>
            </el-form-item>
            <el-form-item label="新密码" prop="newPassword" :rules="[{ required: true, message: '请输入新密码', trigger: 'blur' }, { min: 6, message: '新密码不能少于6位', trigger: 'blur' }]">
              <el-input type="password" v-model="passwords.newPassword" size="large" autocomplete="off"></el-input>
            </el-form-item>
            <el-form-item label="确认新密码" prop="confirmNewPassword" :rules="[{ required: true, message: '请再次输入新密码', trigger: 'blur' }, { validator: validateConfirmPassword, trigger: 'blur' }]">
              <el-input type="password" v-model="passwords.confirmNewPassword" size="large" autocomplete="off"></el-input>
            </el-form-item>
            <el-form-item>
              <el-button type="primary" @click="changePassword" size="large">确认修改</el-button>
            </el-form-item>
          </el-form>
        </div>
        <!-- 商品列表 -->
        <div v-if="activeTab === 'productList'" class="product-list">
          <!-- 搜索栏和排序按钮 -->
         <el-header class="header">
            <div class="content">
              <el-row l-row :gutter="20">
                <!-- 搜索栏 -->
                <el-col :xs="24" :sm="12" :md="8" :lg="6" :xl="6">
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-input v-model='searchName' placeholder='请输入商品名称' clearable></el-input>
                    </el-form-item>
                    <el-form-item>
                      <el-button class="search" type="primary" @click="searchProductsByName">查询</el-button>
                    </el-form-item>
                  </el-form>
                </el-col>
                <el-col :xs="24" :sm="12" :md="8" :lg="6" :xl="6">
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-input v-model='searchContact' placeholder='请输入卖家姓名' clearable></el-input>
                    </el-form-item>
                    <el-form-item>
                      <el-button class="search" type="primary"  @click="searchProductsByContact">查询</el-button>
                    </el-form-item>
                  </el-form>
                </el-col>
                <el-col :xs="24" :sm="12" :md="8" :lg="6" :xl="6">
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-select v-model="searchCategory" placeholder="请选择商品类别" style="width: 200px;">
                        <el-option
                          v-for="item in categories"
                          :key="item.value"
                          :label="item.label"
                          :value="item.value">
                        </el-option>
                      </el-select>
                    </el-form-item>
                    <el-form-item>
                      <el-button class="search" type="primary"  @click="searchProductsByCategory">查询</el-button>
                    </el-form-item>
                  </el-form>
                </el-col>

                <!-- 排序按钮 -->
                <el-col :xs="12" :sm="6" :md="6" :lg="3" :xl="3">
                  <el-form :inline="true" class="form-inline">
                    <div>按价格排序</div>
                    <el-form-item>
                      <el-tooltip content="按价格升序排序" placement="top">
                        <el-button type="primary" @click="sortProductsAscByPrice">
                          <i class="el-icon-caret-top"></i> ⬆
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                    <el-form-item>
                      <el-tooltip content="按价格降序排序" placement="top">
                        <el-button type="primary" @click="sortProductsDescByPrice">
                          <i class="el-icon-caret-bottom"></i> ⬇
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                  </el-form>
                </el-col>
                <el-col :xs="12" :sm="6" :md="6" :lg="3" :xl="3">
                  <div>按上架时间排序</div>
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-tooltip content="按上架时间升序排序" placement="top">
                        <el-button type="primary" @click="sortProductsAscByTime">
                          <i class="el-icon-caret-top"></i> ⬆
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                    <el-form-item>
                      <el-tooltip content="按上架时间降序排序" placement="top">
                        <el-button type="primary" @click="sortProductsDescByTime">
                          <i class="el-icon-caret-bottom"></i> ⬇
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                  </el-form>
                </el-col>
              </el-row>
            </div>
          </el-header>

          <el-table class="products" :data="products" style="width: 100%" align="center">
            <el-table-column prop="productId" label="商品Id" width="65" align="center"></el-table-column>
            <el-table-column prop="category" label="商品类别" width="80" align="center"></el-table-column>
            <el-table-column prop="imageUrl" label="商品图片" width="200" align="center">
              <template #default="scope">
                <img :src="scope.row.imageUrl" alt="商品图片" style="width: 100px; height: auto;">
              </template>
            </el-table-column>
            <el-table-column prop="productName" label="商品名称" width="80" align="center"></el-table-column>
            <el-table-column prop="description" label="商品描述" width="350" align="center"></el-table-column>
            <el-table-column prop="price" label="价格" width="60" align="center"></el-table-column>
            <el-table-column prop="quantity" label="数量" width="60" align="center"></el-table-column>
            <el-table-column label="卖家" width="70" align="center">
              <template #default="scope">
                <el-tooltip content="点击显示详细信息" placement="top" effect="dark">
                  <el-button type="link" @click="showContactDetailsSell(scope.row)">{{ scope.row.contact }}</el-button>
                </el-tooltip>
              </template>
            </el-table-column>
            <el-table-column prop="publishTime" label="上架时间" width="100" align="center"></el-table-column>
            <el-table-column label="操作" width="110" align="center">
              <template #default="scope">
                <el-button size="large" type="danger" @click="removeProduct(scope.row.productId)">下架商品</el-button>
              </template>
            </el-table-column>
          </el-table>

          <!-- 联系人详情对话框 -->
          <el-dialog
            title="卖家详细信息"
            v-model="contactDialogVisible"
            width="30%">
            <div v-if="selectedContact">
              <p><strong>姓名:</strong> {{ selectedContact.username }}</p>
              <p><strong>学号:</strong> {{ selectedContact.studentId }}</p>
              <p><strong>电话:</strong> {{ selectedContact.phone }}</p>
              <p><strong>学院:</strong> {{ selectedContact.college || '暂无' }}</p>
              <p><strong>专业:</strong> {{ selectedContact.major || '暂无' }}</p>
            </div>
            <template #footer>
              <span class="dialog-footer">
                <el-button type="primary" @click="contactDialogVisible = false">确 定</el-button>
              </span>
            </template>
          </el-dialog>

          <!-- 分页按钮 -->
          <div class="pagination-container">
            <el-pagination
              class="custom-pagination"
              layout="prev, pager, next, jumper"
              :total="totalProducts"
              @current-change="handleCurrentChange"
              :current-page="currentPage"
              :page-size="pageSize">
            </el-pagination>
          </div>
        </div>
        <!-- 用户列表 -->
        <div v-if="activeTab === 'userList'" class="user-list">
            <el-table class="user-list" :data="users" style="width: 100%" align="center">
              <el-table-column prop="userId" label=" 用户Id" width="100" align="center"></el-table-column>
              <el-table-column prop="username" label="用户名" width="100" align="center"></el-table-column>
              <el-table-column prop="password" label="密码" width="100" align="center"></el-table-column>
              <el-table-column prop="phone" label="手机号" width="200" align="center"></el-table-column>
              <el-table-column prop="studentId" label="学号" width="200" align="center"></el-table-column>
              <el-table-column prop="college" label="学院" width="200" align="center"></el-table-column>
              <el-table-column prop="major" label="专业" width="100" align="center"></el-table-column>
              <el-table-column prop="status" label="账户状态" width="100" align="center"></el-table-column>
              <el-table-column label="操作" width="100" align="center">
                <template #default="scope">
                  <el-button size="mini" type="danger" @click="editUsers(scope.row.userId)">编辑</el-button>
                </template>
              </el-table-column>
            </el-table>
            <!-- 编辑用户对话框 -->
            <el-dialog :title="dialogTitle" v-model="editDialogVisible" width="50%">
              <el-form :model="editUserFrom" label-width="100px">
                <el-form-item label="用户名">
                  <el-input v-model="editUserFrom.username"></el-input>
                </el-form-item>
                <el-form-item label="密码">
                  <el-input v-model="editUserFrom.password"></el-input>
                </el-form-item>
                <el-form-item label="手机号">
                  <el-input v-model="editUserFrom.phone"></el-input>
                </el-form-item>
                <el-form-item label="学号">
                  <el-input v-model="editUserFrom.studentId"></el-input>
                </el-form-item>
                <el-form-item label="学院">
                  <el-input v-model="editUserFrom.college"></el-input>
                </el-form-item>
                <el-form-item label="专业">
                  <el-input v-model="editUserFrom.major"></el-input>
                </el-form-item>
                <el-form-item label="账户状态">
                  <el-input v-model="editUserFrom.status"></el-input>
                </el-form-item>
              </el-form>
              <template #footer>
              <span class="dialog-footer" style="display: flex; justify-content: center;">
                <el-button type="primary" @click="saveUserChanges">确 定</el-button>
                <el-button @click="editDialogVisible = false">取 消</el-button>
              </span>
            </template>
            </el-dialog>
          <!-- 分页按钮 -->
          <div class="pagination-containerUser">
            <el-pagination
              class="custom-paginationUser"
              layout="prev, pager, next, jumper"
              :total="totalProductsUser"
              @current-change="handleCurrentChangeUser"
              :current-page="currentPageUser"
              :page-size="pageSizeUser">
            </el-pagination>
          </div>
        </div>
        <!-- 数据统计 -->
        <div v-if="activeTab === 'dataStatistics'" class="data-statistics">
          <h1>数据统计</h1>
          <h3>
            <div class="chart-container">
              <div style="width: 50%; height: 30px; display: inline-block;">用户数量统计图</div>
              <div style="width: 50%; height: 30px; display: inline-block;">交易次数统计图</div>
            </div>
          </h3>
          <div class="chart-container">
            <!-- 用户数量统计图 -->
            <div ref="userCountChart" class="chart-item" style="width: 50%; height: 400px; display: inline-block;">
            </div>
            <!-- 交易次数统计图 -->
            <div ref="transactionCountChart" class="chart-item" style="width: 50%; height: 400px; display: inline-block;">
            </div>
          </div>
        </div>
      </el-main>
    </el-container>
  </div>
</template>

  
<script>
  import { ElMessage } from 'element-plus';
  import { useRouter } from 'vue-router';
  import { ref } from 'vue';
  import {onMounted} from 'vue';
  import {nextTick} from 'vue';
  import * as echarts from 'echarts';
  import { watch } from 'vue';
  import CarouselSlider from './CarouselSlider.vue';
  
  export default {
    components: {
      CarouselSlider,
    },
    name: 'MainPage',
    setup() {
      const userProfile = ref({username: '',studentId: '',phone: '',college: '',major: ''});
      const router = useRouter();
      const searchQuery = ref('');
      const products = ref([]);
      const searchName = ref('');
      const searchContact = ref('');
      const searchCategory = ref('');
      const currentSort = ref('');
      const currentPage = ref(1);
      const pageSize = ref(5);
      const totalProductsUser = ref(0);
      const currentPageUser = ref(1);
      const pageSizeUser = ref(10);
      const totalProducts = ref(0);
      const editUserFrom = ref({username: '',password:'',studentId: '',phone: '',college: '',major: '',status:''});
      const activeDialog = ref('');
      const dialogTitle = ref('');
      const dialogVisible = ref(false);
      const editDialogVisible = ref(false);
      const newProduct = ref({ imageUrl:'',  productName: '', description: '', price: '', contact:'', publishTime:''});
      const passwords = ref({ oldPassword: '', newPassword: '', confirmNewPassword: '' });
      const activeTab = ref('mainPage');
      const users = ref([]);
      const userCountChart = ref(null);
      const transactionCountChart = ref(null);
      const userCountData = [120, 200, 150, 80, 70, 110, localStorage.getItem('userCount')];
      const transactionCountData = [80, 120, 90, 130, 110, 140, localStorage.getItem('transactionCount')];
      const selectedContact = ref({username: '',studentId: '',phone: '',college: '',major: ''});
      const contactDialogVisible = ref(false);

      // 在组件挂载时获取信息
      onMounted(() => {
        fetchUserProfile(); 
        fetchProducts(currentPage.value, pageSize.value);
        getAllUser(currentPageUser.value, pageSizeUser.value);
      });

      // 监听统计数据
      watch(activeTab, (newValue) => {
        if (newValue === 'dataStatistics') {
          nextTick(() => {
            // 初始化用户数量统计图
            if (userCountChart.value) {
              const userChart = echarts.init(userCountChart.value);
              const userOption = {
                xAxis: {
                  type: 'category',
                  data: ['2019', '2020', '2021', '2022', '2023', '2024', '2025']
                },
                yAxis: {
                  type: 'value'
                },
                series: [
                  {
                    data: userCountData,
                    type: 'bar',
                    label: {
                      show: true, // 开启显示
                      position: 'top', // 数值显示在柱状图上方
                      formatter: '{c}' // 显示原始数据值
                    }
                  }
                ],
                tooltip: {
                  trigger: 'axis',
                  axisPointer: {
                    type: 'shadow'
                  }
                }
              };
              userChart.setOption(userOption);
            }

            // 初始化交易次数统计图
            if (transactionCountChart.value) {
              const transactionChart = echarts.init(transactionCountChart.value);
              const transactionOption = {
                xAxis: {
                  type: 'category',
                  data: ['2019', '2020', '2021', '2022', '2023', '2024', '2025']
                },
                yAxis: {
                  type: 'value'
                },
                series: [
                  {
                    data: transactionCountData,
                    type: 'bar',
                    label: {
                      show: true, // 开启显示
                      position: 'top', // 数值显示在柱状图上方
                      formatter: '{c}' // 显示原始数据值
                    }
                  }
                ],
                tooltip: {
                  trigger: 'axis',
                  axisPointer: {
                    type: 'shadow'
                  }
                }
              };
              transactionChart.setOption(transactionOption);
            }
          });
        }
      });

      // 监听商品列表
      watch(activeTab, (newValue) => {
        if (newValue === 'dataStatistics') {
          nextTick(() => {
          });
        }
        else if (newValue === 'productList') {
          fetchProducts(currentPage.value, pageSize.value);
        }
      });

      //获取个人信息
      const fetchUserProfile = async () => {
        const token = localStorage.getItem('token');
        const userId = Number(localStorage.getItem('userId'));
        if (!token) {
          ElMessage.error('未获取到认证令牌，请重新登录。');
          return;
        }

        if (!userId) {
          ElMessage.error('未获取到用户ID，请重新登录。');
          return;
        }
        if (isNaN(userId)) {
          // 如果不是有效数字，则进行错误处理
          console.error("Invalid userId: " + userId);
        }

        try {
          const response = await fetch(`http://localhost:8080/api/user/information/${userId}`, {
            method: 'GET',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token
            },
          });
          if (!response.ok) {
            throw new Error('获取用户信息失败，状态码：' + response.status);
          }
          const data = await response.json();
          userProfile.value = data; 
        } catch (error) {
          ElMessage.error('获取用户信息失败：' + error.message);
        }
      };

      //修改个人信息
      const updateUserProfile = async () => {
        const token = localStorage.getItem('token');
        const userId = localStorage.getItem('userId');
        if (!token) {
          ElMessage.error('未获取到认证令牌，请重新登录。');
          return;
        }

        if (!userId) {
          ElMessage.error('未获取到用户ID，请重新登录。');
          return;
        }

        const userProfileData = userProfile.value || {};
        // 添加userId到请求体
        userProfileData.userId = userId;

        try {
          const response = await fetch('http://localhost:8080/api/user/profile', {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token
            },
            body: JSON.stringify(userProfile.value)
          });

          if (!response.ok) {
            throw new Error('个人信息更新失败，状态码：' + response.status);
          }
          const data = await response.json();
          ElMessage.success(data.message || '个人信息更新成功！');
          dialogVisible.value = false;
        } catch (error) {
          ElMessage.error('个人信息更新失败：' + error.message);
        }
      };

      //修改密码
      const changePassword = async () => {
        if (!passwords.value.oldPassword || !passwords.value.newPassword || !passwords.value.confirmNewPassword) {
          ElMessage.error('请填写完整的密码信息！');
          return;
        }
        if (passwords.value.newPassword.length < 6 || passwords.value.newPassword.length > 20) {
          ElMessage.error('新密码长度应该为6-20位！');
          return;
        }
        if (passwords.value.newPassword !== passwords.value.confirmNewPassword) {
          ElMessage.error('两次输入的新密码不一致！');
          return;
        }
        const token = localStorage.getItem('token');
        if (!token) {
          ElMessage.error('未获取到认证令牌，请重新登录。');
          return;
        }
        try {
          const response = await fetch('http://localhost:8080/api/user/password?userId=' + localStorage.getItem('userId'), {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token,
            },
            body: JSON.stringify(passwords.value),
          });

          if (!response.ok) {
            throw new Error('旧密码错误！');
          }

          ElMessage.success('密码更改成功！');
        } catch (error) {
          ElMessage.error('密码更改失败：' + error.message);
        }
      };

      //退出登录
      const logout = async () => {
          localStorage.removeItem('token');
          sessionStorage.removeItem('userProfile');
          ElMessage.success('退出登录成功！');
          router.push('/');
      };

      //格式化上架时间
      const formatDate = (isoDate) => {
        const date = new Date(isoDate);
        return `${date.getFullYear()}.${date.getMonth() + 1}.${date.getDate()}`;
      };

      //获取全部用户信息
      const getAllUser = async (page,size) => {
        try {
          const response = await fetch(`http://localhost:8080/api/user/all?page=${page}&size=${size}`, {
            method: 'GET',
            headers: {
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
            },
          });
          if (!response.ok) {
            throw new Error('Network response was not ok.');
          }
          const data = await response.json();
          console.log(data);
          users.value = data.content || [];
