<template>
  <div class="main-page">
    <el-container style="height: 100vh;">
      <!-- 添加一个头部导航栏 -->
      <el-header class="header-nav">
        <div class="nav-content">
          <span class="title">校园二手交易平台</span>
        </div>
      </el-header>
      <el-aside class="fixed-aside" width="200px">
        <el-menu default-active="0" class="el-menu-vertical-demo">
          <el-menu-item index="0" @click="activeTab = 'mainPage'">
            <i class="el-icon-main"></i>
            <template #title>首页</template>
          </el-menu-item>
          <el-menu-item index="1" @click="activeTab = 'editProfile'">
            <i class="el-icon-user"></i>
            <template #title>修改个人信息</template>
          </el-menu-item>
          <el-menu-item index="2" @click="activeTab = 'changePassword'">
            <i class="el-icon-lock"></i>
            <template #title>修改密码</template>
          </el-menu-item>
          <el-menu-item index="3" @click="activeTab = 'productList'">
            <i class="el-icon-s-goods"></i>
            <template #title>商品列表</template>
          </el-menu-item>
          <el-menu-item index="4" @click="activeTab =  'addProduct'">
            <i class="el-icon-plus"></i>
            <template #title>上架商品</template>
          </el-menu-item>
          <el-menu-item index="5" @click="activeTab = 'myProducts'">
            <i class="el-icon-setting"></i>
            <template #title>管理我的商品</template>
          </el-menu-item>
          <el-menu-item index="6" @click="activeTab = 'shoppingCart'">
            <i class="el-icon-shopping-cart-full"></i>
            <template #title>购物车</template>
          </el-menu-item>
          <el-menu-item index="7" @click="activeTab = 'historicalOrder'">
            <i class="el-icon-historicalOrder"></i>
            <template #title>历史订单</template>
          </el-menu-item>
          <el-menu-item index="8" @click="logout">
            <i class="el-icon-switch-button"></i>
            <template #title>退出登录</template>
          </el-menu-item>
        </el-menu>
      </el-aside>
      <el-main class="main-content" style="padding-right: 250px;">
        <!-- 首页 -->
        <div v-if="activeTab === 'mainPage'" class="main-page-content">
          <h1>欢迎来到校园二手交易平台</h1>
          <div class="carousel-container">
            <CarouselSlider />
          </div>
        </div>
        <!-- 修改个人信息 -->
        <div v-if="activeTab === 'editProfile'" class="edit-profile">
          <el-form :model="userProfile" label-width="100px"> 
            <el-form-item label="用户名">
              <el-input v-model="userProfile.username" size="large"></el-input>
            </el-form-item>
            <el-form-item label="学号">
              <el-input v-model="userProfile.studentId" size="large"></el-input>
            </el-form-item>
            <el-form-item label="手机号">
              <el-input v-model="userProfile.phone" size="large"></el-input>
            </el-form-item>
            <el-form-item label="学院">
              <el-input v-model="userProfile.college" size="large"></el-input>
            </el-form-item>
            <el-form-item label="专业">
              <el-input v-model="userProfile.major" size="large"></el-input>
            </el-form-item>
            <el-form-item>
              <el-button type="primary" @click="updateUserProfile" size="large">保存</el-button>
            </el-form-item>
          </el-form>
        </div>
        <!-- 修改密码 -->
        <div v-if="activeTab === 'changePassword'" class="change-password">
          <el-form :model="passwords" ref="passwordForm" @submit.prevent="changePassword" label-width="100px">
            <el-form-item label="旧密码" prop="oldPassword" :rules="[{ required: true, message: '请输入旧密码', trigger: 'blur' }]">
              <el-input type="password" v-model="passwords.oldPassword" size="large" autocomplete="off"></el-input>
            </el-form-item>
            <el-form-item label="新密码" prop="newPassword" :rules="[{ required: true, message: '请输入新密码', trigger: 'blur' }, { min: 6, message: '新密码不能少于6位', trigger: 'blur' }]">
              <el-input type="password" v-model="passwords.newPassword" size="large" autocomplete="off"></el-input>
            </el-form-item>
            <el-form-item label="确认新密码" prop="confirmNewPassword" :rules="[{ required: true, message: '请再次输入新密码', trigger: 'blur' }, { validator: validateConfirmPassword, trigger: 'blur' }]">
              <el-input type="password" v-model="passwords.confirmNewPassword" size="large" autocomplete="off"></el-input>
            </el-form-item>
            <el-form-item>
              <el-button type="primary" @click="changePassword" size="large">确认修改</el-button>
            </el-form-item>
          </el-form>
        </div>
        <!-- 商品列表 -->
        <div v-if="activeTab === 'productList'" class="product-list">
          <!-- 搜索栏和排序按钮 -->
         <el-header class="header">
            <div class="content">
              <el-row l-row :gutter="20">
                <!-- 搜索栏 -->
                <el-col :xs="24" :sm="12" :md="8" :lg="6" :xl="6">
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-input v-model='searchName' placeholder='请输入商品名称' clearable></el-input>
                    </el-form-item>
                    <el-form-item>
                      <el-button class="search" type="primary" @click="searchProductsByName">查询</el-button>
                    </el-form-item>
                  </el-form>
                </el-col>
                <el-col :xs="24" :sm="12" :md="8" :lg="6" :xl="6">
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-input v-model='searchContact' placeholder='请输入卖家姓名' clearable></el-input>
                    </el-form-item>
                    <el-form-item>
                      <el-button class="search" type="primary"  @click="searchProductsByContact">查询</el-button>
                    </el-form-item>
                  </el-form>
                </el-col>
                <el-col :xs="24" :sm="12" :md="8" :lg="6" :xl="6">
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-select v-model="searchCategory" placeholder="请选择商品类别" style="width: 200px;">
                        <el-option
                          v-for="item in categories"
                          :key="item.value"
                          :label="item.label"
                          :value="item.value">
                        </el-option>
                      </el-select>
                    </el-form-item>
                    <el-form-item>
                      <el-button class="search" type="primary"  @click="searchProductsByCategory">查询</el-button>
                    </el-form-item>
                  </el-form>
                </el-col>

                <!-- 排序按钮 -->
                <el-col :xs="12" :sm="6" :md="6" :lg="3" :xl="3">
                  <el-form :inline="true" class="form-inline">
                    <div>按价格排序</div>
                    <el-form-item>
                      <el-tooltip content="按价格升序排序" placement="top">
                        <el-button type="primary" @click="sortProductsAscByPrice">
                          <i class="el-icon-caret-top"></i> ⬆
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                    <el-form-item>
                      <el-tooltip content="按价格降序排序" placement="top">
                        <el-button type="primary" @click="sortProductsDescByPrice">
                          <i class="el-icon-caret-bottom"></i> ⬇
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                  </el-form>
                </el-col>
                <el-col :xs="12" :sm="6" :md="6" :lg="3" :xl="3">
                  <div>按上架时间排序</div>
                  <el-form :inline="true" class="form-inline">
                    <el-form-item>
                      <el-tooltip content="按上架时间升序排序" placement="top">
                        <el-button type="primary" @click="sortProductsAscByTime">
                          <i class="el-icon-caret-top"></i> ⬆
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                    <el-form-item>
                      <el-tooltip content="按上架时间降序排序" placement="top">
                        <el-button type="primary" @click="sortProductsDescByTime">
                          <i class="el-icon-caret-bottom"></i> ⬇
                        </el-button>
                      </el-tooltip>
                    </el-form-item>
                  </el-form>
                </el-col>
              </el-row>
            </div>
          </el-header>

          <el-table class="products" :data="products" style="width: 100%" align="center">
            <el-table-column prop="productId" label="商品Id" width="65" align="center"></el-table-column>
            <el-table-column prop="category" label="商品类别" width="80" align="center"></el-table-column>
            <el-table-column prop="imageUrl" label="商品图片" width="200" align="center">
              <template #default="scope">
                <img :src="scope.row.imageUrl" alt="商品图片" style="width: 100px; height: auto;">
              </template>
            </el-table-column>
            <el-table-column prop="productName" label="商品名称" width="80" align="center"></el-table-column>
            <el-table-column prop="description" label="商品描述" width="350" align="center"></el-table-column>
            <el-table-column prop="price" label="价格" width="60" align="center"></el-table-column>
            <el-table-column prop="quantity" label="数量" width="60" align="center"></el-table-column>
            <el-table-column label="卖家" width="70" align="center">
              <template #default="scope">
                <el-tooltip content="点击显示详细信息" placement="top" effect="dark">
                  <el-button type="link" @click="showContactDetailsSell(scope.row)">{{ scope.row.contact }}</el-button>
                </el-tooltip>
              </template>
            </el-table-column>
            <el-table-column prop="publishTime" label="上架时间" width="100" align="center"></el-table-column>
            <el-table-column label="操作" width="110" align="center">
              <template #default="scope">
                <el-button size="large" @click="addCartItem(scope.row)">添加至购物车</el-button>
              </template>
            </el-table-column>
          </el-table>

          
          <!-- 分页按钮 -->
          <div class="pagination-container">
            <el-pagination
              class="custom-pagination"
              layout="prev, pager, next, jumper"
              :total="totalProducts"
              @current-change="handleCurrentChange"
              :current-page="currentPage"
              :page-size="pageSize">
            </el-pagination>
          </div>

          <!-- 联系人详情对话框 -->
          <el-dialog
            title="卖家详细信息"
            v-model="contactDialogVisible"
            width="30%">
            <div v-if="selectedContact">
              <p><strong>姓名:</strong> {{ selectedContact.username }}</p>
              <p><strong>学号:</strong> {{ selectedContact.studentId }}</p>
              <p><strong>电话:</strong> {{ selectedContact.phone }}</p>
              <p><strong>学院:</strong> {{ selectedContact.college || '暂无' }}</p>
              <p><strong>专业:</strong> {{ selectedContact.major || '暂无' }}</p>
            </div>
            <template #footer>
              <span class="dialog-footer">
                <el-button type="primary" @click="contactDialogVisible = false">确 定</el-button>
              </span>
            </template>
          </el-dialog>
        </div>
        <!-- 上架商品 -->
        <div v-if="activeTab === 'addProduct'" class="add-product">
          <el-form ref="productForm" :model="newProduct" label-width="100px">
              <!-- 商品照片上传 -->
              <el-form-item label="商品图片">
                  <el-upload
                      class="avatar-uploader"
                      action="http://localhost:8080/api/product/image"
                      :show-file-list="false"
                      :on-change="handleFileChange"
                      :before-upload="beforeAvatarUpload"
                      :on-success="handleUploadSuccess"
                      ref="upload">
                      <div v-if="newProduct.imageUrl" class="upload-icon">
                          <img :src="newProduct.imageUrl" class="avatar">
                      </div>
                      <div v-else class="upload-icon" @click="dialogVisible = true">
                          <i class="el-icon-plus avatar-uploader-icon"></i>
                      </div>
                  </el-upload>
              </el-form-item>
              <!-- 商品名称 -->
              <el-form-item label="商品名称">
                  <el-input type="textarea"
                      :rows="4"
                      placeholder="请输入商品名称" 
                      v-model="newProduct.productName" 
                      size="large">
                  </el-input>
              </el-form-item>
              <!-- 商品描述 -->
              <el-form-item label="商品描述">
                  <el-input
                      type="textarea"
                      :rows="4"
                      placeholder="请输入商品描述(最多50个字)"
                      v-model="newProduct.description"
                      maxlength="50"
                      show-word-limit>
                  </el-input>
              </el-form-item>
              <!-- 商品类别 -->
              <el-form-item label="商品类别">
                  <el-select v-model="newProduct.category" placeholder="请选择商品类别" size="large">
                      <el-option
                          v-for="item in categories"
                          :key="item.value"
                          :label="item.label"
                          :value="item.value">
                      </el-option>
                  </el-select>
              </el-form-item>
              <!-- 商品价格 -->
              <el-form-item label="商品价格">
                  <el-input-number v-model="newProduct.price" :min="0" size="large" controls-position="right"></el-input-number>
              </el-form-item>
              <!-- 商品数量 -->
              <el-form-item label="商品数量">
                  <el-input-number v-model="newProduct.quantity" :min="0" size="large" controls-position="right"></el-input-number>
              </el-form-item>
              <!-- 提交按钮 -->
              <el-form-item>
                  <el-button type="primary" @click="addProduct" size="large">确认上架</el-button>
              </el-form-item>
          </el-form>
        </div>
        <!-- 管理我的商品 -->
        <div v-if="activeTab === 'myProducts'" class="my-products">
          <el-table class="manage" :data="myProducts" style="width: 100%" align="center">
            <el-table-column prop="productId" label="商品Id" width="80" align="center"></el-table-column>
            <el-table-column prop="category" label="商品类别" width="80" align="center"></el-table-column>
            <el-table-column prop="imageUrl" label="商品图片" width="300" align="center">
              <template #default="scope">
                <img :src="scope.row.imageUrl" alt="商品图片" style="width: 100px; height: auto;">
              </template>
            </el-table-column>
            <el-table-column prop="productName" label="商品名称" width="80" align="center"></el-table-column>
            <el-table-column prop="description" label="商品描述" width="300" align="center"></el-table-column>
            <el-table-column prop="price" label="价格" width="80" align="center"></el-table-column>
            <el-table-column prop="quantity" label="数量" width="80" align="center"></el-table-column>
            <el-table-column label="修改" width="90" align="center">
              <template #default="scope">
                <div style="text-align: center;">
                  <el-button size="small" @click="editProduct(scope.row.productId)">编辑</el-button>
                </div>
              </template>
            </el-table-column>
            <el-table-column label="操作" width="100" align="center">
              <template #default="scope">
                <div style="text-align: center;">
                  <el-button 
                    size="small" 
                    :type="scope.row.productStatus === '1' ? 'danger' : 'success'"
                    @click="scope.row.productStatus === '1' ? removeProduct(scope.row.productId) : addProductStatus(scope.row.productId)">
                    {{ scope.row.productStatus === '1' ? '下架' : '上架' }}
                  </el-button>
                </div>
              </template>
            </el-table-column>
          </el-table>
          <!-- 编辑商品对话框 -->
          <el-dialog title="编辑商品" v-model="editDialogVisible">
            <el-form :model="editProductfrom" label-width="100px" label-position="left">
              <!-- 商品类别选择 -->
              <el-form-item label="商品类别">
                <el-select v-model="editProductfrom.category" placeholder="请选择商品类别">
                  <el-option
                    v-for="item in categories"
                    :key="item.value"
                    :label="item.label"
                    :value="item.value">
                  </el-option>
                </el-select>
              </el-form-item>
              <!-- 商品名称 -->
              <el-form-item label="商品名称">
                <el-input v-model="editProductfrom.productName" autocomplete="off"></el-input>
              </el-form-item>
              <!-- 商品描述 -->
              <el-form-item label="商品描述">
                <el-input v-model="editProductfrom.description" autocomplete="off"></el-input>
              </el-form-item>
              <!-- 价格 -->
              <el-form-item label="价格">
                <el-input-number v-model="editProductfrom.price" :min="1" controls-position="right"></el-input-number>
              </el-form-item>
              <!-- 数量 -->
              <el-form-item label="数量">
                <el-input-number v-model="editProductfrom.quantity" :min="1" controls-position="right"></el-input-number>
              </el-form-item>
            </el-form>
            <template #footer>
              <span class="dialog-footer" style="display: flex; justify-content: center;">
                <el-button type="primary" @click="confirmEdit(productId)">确 定</el-button>
                <el-button @click="editDialogVisible = false">取 消</el-button>
              </span>
            </template>
          </el-dialog>
          <!-- 分页按钮 -->
          <div class="pagination-containerMy">
            <el-pagination
              class="custom-paginationMy"
              layout="prev, pager, next, jumper"
              :total="totalProductsMy"
              @current-change="handleCurrentChangeMy"
              :current-page="currentPageMy"
              :page-size="pageSizeMy">
            </el-pagination>
          </div>
        </div>
        <!-- 购物车 -->
        <div v-if="activeTab === 'shoppingCart'" class="shopping-cart">
            <el-table class="shopping-cart" :data="cartItems" style="width: 100%" align="center">
              <el-table-column prop="cartId" label="购物车Id" width="100" align="center"></el-table-column>
              <el-table-column prop="category" label="商品类别" width="80" align="center"></el-table-column>
              <el-table-column prop="imageUrl" label="商品图片" width="300" align="center">
                <template #default="scope">
                  <img :src="scope.row.imageUrl" alt="商品图片" style="width: 100px; height: auto;">
                </template>
              </el-table-column>
              <el-table-column prop="productName" label="商品名称" width="80" align="center"></el-table-column>
              <el-table-column prop="description" label="商品描述" width="300" align="center"></el-table-column>
              <el-table-column label="卖家" width="70" align="center">
                <template #default="scope">
                  <el-tooltip content="点击显示详细信息" placement="top" effect="dark">
                    <el-button type="link" @click="showContactDetailsSell(scope.row)">{{ scope.row.contact }}</el-button>
                  </el-tooltip>
                </template>
              </el-table-column>
              <el-table-column prop="price" label="价格" width="80" align="center"></el-table-column>
              <el-table-column label="操作" width="80" align="center">
                <template #default="scope">
                  <el-button size="mini" type="danger" @click="deleteCartItems(scope.row.cartId)">移除</el-button>
                </template>
              </el-table-column>
              <el-table-column label="操作" width="80" align="center">
                <template #default="scope">
                  <el-button size="mini"  @click="payCartItems(scope.row.cartId)">支付</el-button>
                </template>
              </el-table-column>
            </el-table>
          <!-- 分页按钮 -->
          <div class="pagination-containerCart">
            <el-pagination
              class="custom-paginationCart"
              layout="prev, pager, next, jumper"
              :total="totalProductsCart"
              @current-change="handleCurrentChangeCart"
              :current-page="currentPageCart"
              :page-size="pageSizeCart">
            </el-pagination>
          </div>

            <!-- 联系人详情对话框 -->
            <el-dialog
            title="卖家详细信息"
            v-model="contactDialogVisible"
            width="30%">
            <div v-if="selectedContact">
              <p><strong>姓名:</strong> {{ selectedContact.username }}</p>
              <p><strong>学号:</strong> {{ selectedContact.studentId }}</p>
              <p><strong>电话:</strong> {{ selectedContact.phone }}</p>
              <p><strong>学院:</strong> {{ selectedContact.college || '暂无' }}</p>
              <p><strong>专业:</strong> {{ selectedContact.major || '暂无' }}</p>
            </div>
            <template #footer>
              <span class="dialog-footer">
                <el-button type="primary" @click="contactDialogVisible = false">确 定</el-button>
              </span>
            </template>
          </el-dialog>
        </div>
        <!-- 历史订单 -->
        <div v-if="activeTab === 'historicalOrder'" class="historical-order">
            <el-table class="historical-order" :data="orderItems" style="width: 100%" align="center">
              <el-table-column prop="orderId" label="订单Id" width="80" align="center"></el-table-column>
              <el-table-column prop="category" label="商品类别" width="80" align="center"></el-table-column>
              <el-table-column prop="imageUrl" label="商品图片" width="250" align="center">
                <template #default="scope">
                  <img :src="scope.row.imageUrl" alt="商品图片" style="width: 100px; height: auto;">
                </template>
              </el-table-column>
              <el-table-column prop="productName" label="商品名称" width="80" align="center"></el-table-column>
              <el-table-column prop="description" label="商品描述" width="300" align="center"></el-table-column>
              <el-table-column label="买家" width="80" align="center">
                <template #default="scope">
                  <el-tooltip content="点击显示详细信息" placement="top" effect="dark">
                    <el-button type="link" @click="showContactDetailsBuy(scope.row)">{{ scope.row.username }}</el-button>
                  </el-tooltip>
                </template>
              </el-table-column>
              <el-table-column prop="price" label="价格" width="80" align="center"></el-table-column>
              <el-table-column prop="orderTime" label="订单时间" width="80" align="center"></el-table-column>
              <el-table-column prop="status" label="订单状态" width="80" align="center"></el-table-column>
              <el-table-column label="操作" width="80" align="center">
                <template #default="scope">
                  <el-button size="mini" type="danger" @click="deleteOrders(scope.row.orderId)">删除订单</el-button>
                </template>
              </el-table-column>
            </el-table>
          <!-- 分页按钮 -->
          <div class="pagination-containerOrder">
            <el-pagination
              class="custom-paginationOrder"
              layout="prev, pager, next, jumper"
              :total="totalProductsOrder"
              @current-change="handleCurrentChangeOrder"
              :current-page="currentPageOrder"
              :page-size="pageSizeOrder">
            </el-pagination>
          </div>
          <!-- 买家详情对话框 -->
          <el-dialog
            title="买家详细信息"
            v-model="usernameDialogVisible"
            width="30%">
            <div v-if="selectedUsername">
              <p><strong>姓名:</strong> {{ selectedUsername.username }}</p>
