      const selectedUsername = ref({username: '',studentId: '',phone: '',college: '',major: ''});

      // 在组件挂载时获取信息
      onMounted(() => {
        fetchUserProfile();
        fetchProducts(currentPage.value, pageSize.value);
        getMyProduct(currentPageMy.value, pageSizeMy.value);
        getCartItems(currentPageCart.value, pageSizeCart.value);
        getorderItems(currentPageOrder.value, pageSizeOrder.value);
      });

      // 监听商品列表
      watch(activeTab, (newValue) => {
        if (newValue === 'dataStatistics') {
          nextTick(() => {
          });
        }
        else if (newValue === 'productList') {
          fetchProducts(currentPage.value, pageSize.value);
        }
      });

      // 获取个人信息
      const fetchUserProfile = async () => {
        const token = localStorage.getItem('token');
        const userId = Number(localStorage.getItem('userId'));
        if (!token) {
          ElMessage.error('未获取到认证令牌，请重新登录。');
          return;
        }

        if (!userId) {
          ElMessage.error('未获取到用户ID，请重新登录。');
          return;
        }
        if (isNaN(userId)) {
          // 如果不是有效数字，则进行错误处理
          console.error("Invalid userId: " + userId);
        }

        try {
          const response = await fetch(`http://localhost:8080/api/user/information/${userId}`, {
            method: 'GET',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token
            },
          });
          if (!response.ok) {
            throw new Error('获取用户信息失败，状态码：' + response.status);
          }
          const data = await response.json();
          userProfile.value = data; 
        } catch (error) {
          ElMessage.error('获取用户信息失败：' + error.message);
        }
      };

      // 修改个人信息
      const updateUserProfile = async () => {
        const token = localStorage.getItem('token');
        const userId = localStorage.getItem('userId');
        if (!token) {
          ElMessage.error('未获取到认证令牌，请重新登录。');
          return;
        }

        if (!userId) {
          ElMessage.error('未获取到用户ID，请重新登录。');
          return;
        }

        const userProfileData = userProfile.value || {};
        // 添加userId到请求体
        userProfileData.userId = userId;

        try {
          const response = await fetch('http://localhost:8080/api/user/profile', {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token
            },
            body: JSON.stringify(userProfile.value)
          });

          if (!response.ok) {
            throw new Error('个人信息更新失败，状态码：' + response.status);
          }
          const data = await response.json();
          ElMessage.success(data.message || '个人信息更新成功！');
          dialogVisible.value = false;
        } catch (error) {
          ElMessage.error('个人信息更新失败：' + error.message);
        }
      };

      // 修改密码
      const changePassword = async () => {
        if (!passwords.value.oldPassword || !passwords.value.newPassword || !passwords.value.confirmNewPassword) {
          ElMessage.error('请填写完整的密码信息！');
          return;
        }
        if (passwords.value.newPassword.length < 6 || passwords.value.newPassword.length > 20) {
          ElMessage.error('新密码长度应该为6-20位！');
          return;
        }
        if (passwords.value.newPassword !== passwords.value.confirmNewPassword) {
          ElMessage.error('两次输入的新密码不一致！');
          return;
        }
        const token = localStorage.getItem('token');
        if (!token) {
          ElMessage.error('未获取到认证令牌，请重新登录。');
          return;
        }
        try {
          const response = await fetch('http://localhost:8080/api/user/password?userId=' + localStorage.getItem('userId'), {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token,
            },
            body: JSON.stringify(passwords.value),
          });

          if (!response.ok) {
            throw new Error('旧密码错误！');
          }

          ElMessage.success('密码更改成功，请重新登录！');
          router.push('/');
        } catch (error) {
          ElMessage.error('密码更改失败：' + error.message);
        }
      };

      // 退出登录
      const logout = async () => {
          localStorage.removeItem('token');
          sessionStorage.removeItem('userProfile');
          ElMessage.success('退出登录成功！');
          router.push('/');
      };

      // 格式化上架时间
      const formatDate = (isoDate) => {
        const date = new Date(isoDate);
        return `${date.getFullYear()}.${date.getMonth() + 1}.${date.getDate()}`;
      };

      // 分页改变时的处理函数
      const handleCurrentChange = async (newPage) => {
          currentPage.value = newPage;
          let url = '';
          switch (currentSort.value) {
              case 'price_asc':
                  url = `http://localhost:8080/api/product/price/asc?page=${currentPage.value}&size=${pageSize.value}`;
                  break;
              case 'price_desc':
                  url = `http://localhost:8080/api/product/price/desc?page=${currentPage.value}&size=${pageSize.value}`;
                  break;
              case 'publishTime_asc':
                  url = `http://localhost:8080/api/product/publishTime/asc?page=${currentPage.value}&size=${pageSize.value}`;
                  break;
              case 'publishTime_desc':
                  url = `http://localhost:8080/api/product/publishTime/desc?page=${currentPage.value}&size=${pageSize.value}`;
                  break;
              default:
                  // 默认加载所有商品
                  url = `http://localhost:8080/api/product/all?page=${currentPage.value}&size=${pageSize.value}`;
          }

          try {
              const response = await fetch(url, {
                  method: 'GET',
                  headers: {
                      'Authorization': 'Bearer ' + localStorage.getItem('token'),
                  }
              });

              if (!response.ok) {
                  throw new Error('Network response was not ok');
              }

              const data = await response.json();
              products.value = data.content.map(product => ({
                  ...product,
                  publishTime: formatDate(product.publishTime)
              }));
              totalProducts.value = data.totalElements || 0;
          } catch (error) {
              ElMessage.error('获取数据失败：' + error.message);
          }
      };

      // 获取商品信息
      const fetchProducts = async (page, size) => {
        try {
          const response = await fetch(`http://localhost:8080/api/product/all?page=${page}&size=${size}`, {
            method: 'GET',
            headers: {
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
            },
          });
          if (!response.ok) {
            throw new Error('Network response was not ok.');
          }
          const data = await response.json();
          console.log("全部商品信息：",data);
          products.value = data.content ? data.content.map(product => ({
            ...product,
            publishTime: formatDate(product.publishTime)
        })) : [];
          totalProducts.value = data.totalElements || 0;
        } catch (error) {
          ElMessage.error('获取商品信息失败：' + error.message);
        }
      };

      // 按商品名称查询
      const searchProductsByName = async () => {
        if (!searchName.value.trim()) {
          ElMessage.warning('请输入商品名称');
          return;
        }
        
        try {
          const response = await fetch(
            `http://localhost:8080/api/product/search/productName/${searchName.value}?page=${currentPage.value}&size=${pageSize.value}`, 
            {
              method: 'GET',
              headers: {
                'Authorization': 'Bearer ' + localStorage.getItem('token'),
              }
            }
          );
          
          if (!response.ok) {
            throw new Error('Network response was not ok');
          }
          
          const data = await response.json();
          products.value = data.content.map(product => ({
            ...product,
            publishTime: formatDate(product.publishTime)
          }));
          totalProducts.value = data.totalElements || 0;
        } catch (error) {
          ElMessage.error('查询失败：' + error.message);
        }
      };

      // 按联系人查询
      const searchProductsByContact = async () => {
        if (!searchContact.value.trim()) {
          ElMessage.warning('请输入联系人');
          return;
        }
        
        try {
          const response = await fetch(
            `http://localhost:8080/api/product/search/contact/${searchContact.value}?page=${currentPage.value}&size=${pageSize.value}`, 
            {
              method: 'GET',
