          } catch (error) {
              ElMessage.error('排序失败：' + error.message);
          }
      };

      // 显示卖家详细信息
      const showContactDetailsSell = async (row) => {
        try {
          const token = localStorage.getItem('token');
          if (!token) {
            ElMessage.error('未获取到认证令牌，请重新登录。');
            return;
          }

          const response = await fetch(`http://localhost:8080/api/user/details/sell/${row.contact}`, {
            method: 'GET',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token
            },
          });

          if (!response.ok) {
            throw new Error('获取联系人详细信息失败');
          }

          const data = await response.json();
          selectedContact.value = {
            username: data.username,
            studentId: data.studentId,
            phone: data.phone,
            college: data.college || '暂无',
            major: data.major || '暂无'
          };
          console.log('API Response:', data);  // 检查API返回的数据
          console.log('Selected Contact:', selectedContact.value);  // 检查赋值后的数据
          contactDialogVisible.value = true;
        } catch (error) {
          console.error('获取联系人信息失败:', error);
