          const response = await fetch(`http://localhost:8080/api/user/details/buy/${row.username}`, {
            method: 'GET',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + token
            },
          });

          if (!response.ok) {
            throw new Error('获取联系人详细信息失败');
          }

          const data = await response.json();
          selectedUsername.value = {
            username: data.username,
            studentId: data.studentId,
            phone: data.phone,
            college: data.college || '暂无',
            major: data.major || '暂无'
          };
          console.log('API Response:', data);  // 检查API返回的数据
          console.log('Selected Contact:', selectedUsername.value);  // 检查赋值后的数据
          usernameDialogVisible.value = true;
        } catch (error) {
          console.error('获取联系人信息失败:', error);
          ElMessage.error('获取联系人信息失败');
        }
      };

      // 添加商品到购物车
      const addCartItem = async (product) => {
        try {
          // 获取当前登录用户的用户名
          const username = localStorage.getItem('username');

          // 确保当前用户名存在
          if (!username) {
            throw new Error('当前用户信息未找到，请重新登录！');
          }

          // 检查商品库存是否足够
          if (product.quantity <= 0) {
            throw new Error('该商品库存不足！');
          }

          // 发送请求添加商品到购物车
          const response = await fetch(`http://localhost:8080/api/shoppingCart/add/${username}`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
            },
            body: JSON.stringify(product),
          });

          if (!response.ok) {
            throw new Error('Network response was not ok.');
          }

          const data = await response.json();
          cartItems.value.push(data);
          
          await fetch(`http://localhost:8080/api/product/updateQuantity/${product.productId}`, {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
            },
            body: JSON.stringify(),
          });

          fetchProducts(currentPage.value, pageSize.value);
          getCartItems(currentPageCart.value, pageSizeCart.value);
          localStorage.setItem('productId',product.productId);
          ElMessage.success('商品已添加到购物车！');
        } catch (error) {
          ElMessage.error('添加到购物车失败：' + error.message);
        }
      };

      // 上架商品
      const addProduct = async () => {
          try {
              // 获取当前登录用户的用户名
              const currentUsername = localStorage.getItem('username');

              // 确保当前用户名存在
              if (!currentUsername) {
                  throw new Error('当前用户信息未找到，请重新登录！');
              }

              // 设置联系人为当前登录用户的用户名
              newProduct.value.contact = currentUsername;

              // 设置发布时间
              newProduct.value.publishTime = new Date().toISOString();

              // 上传图片并获取图片路径
              if (newProduct.value.imageFile) {
                  const imageUrl = await handleUpload(newProduct.value.imageFile);
                  newProduct.value.imageUrl = imageUrl;
              }
              newProduct.value.productStatus = '1';

              console.log('New Product:', newProduct.value);

              // 发送请求上架商品
              const response = await fetch('http://localhost:8080/api/product', {
                  method: 'POST',
                  headers: {
                      'Content-Type': 'application/json',
                      'Authorization': 'Bearer ' + localStorage.getItem('token'),
                  },
                  body: JSON.stringify(newProduct.value),
              });

              if (!response.ok) {
                  throw new Error('Network response was not ok.');
              }

              const data = await response.json();
              products.value.push(data.product);
              ElMessage.success('商品上架成功！');
              getMyProduct(currentPageMy.value, pageSizeMy.value);
              dialogVisible.value = false;
          } catch (error) {
              ElMessage.error('商品上架失败：' + error.message);
          }
      };

      // 上传图片并返回图片路径
      const handleUpload = async (file) => {
          if (beforeAvatarUpload(file)) {
              const formData = new FormData();
              formData.append('image', file);
              try {
                  const response = await fetch('http://localhost:8080/api/product/image', {
                      method: 'POST',
                      headers: {
                          'Authorization': 'Bearer ' + localStorage.getItem('token'),
                      },
                      body: formData,
                  });
                  if (response.ok) {
                      const data = await response.json();
                      return data.imageUrl;
                  } else {
                      const errorData = await response.json();
                      throw new Error('图片上传失败: ' + errorData);
                  }
              } catch (error) {
                  console.error('上架商品时发生错误:', error);
                  throw error;
              }
          }
      };

      // 上传图片前的检查
      const beforeAvatarUpload = (file) => {
          const isJPG = file.type === 'image/jpeg';
          const isPNG = file.type === 'image/png';
          const isLt2M = file.size / 1024 / 1024 < 2;

          if (!isJPG && !isPNG) {
              ElMessage.error('上传头像图片只能是 JPG/PNG 格式!');
              return false;
          }
          if (!isLt2M) {
              ElMessage.error('上传头像图片大小不能超过 2MB!');
              return false;
          }
          return true;
      };

      // 处理文件选择变化
      const handleFileChange = (file) => {
          const reader = new FileReader();
          reader.onload = (e) => {
              newProduct.value.imageUrl = e.target.result;
          };
          reader.readAsDataURL(file.raw);
          newProduct.value.imageFile = file.raw;
      };

      // 处理上传成功
      const handleUploadSuccess = (response) => {
          newProduct.value.imageUrl = response.imageUrl;
      };
      
      // 获取我的商品信息
      const getMyProduct = async (page, size) => {
