        if(!productId){
          ElMessage.error('未获取到商品ID，请重新登录。');
          return;
        }

        try {
          const response = await fetch(`http://localhost:8080/api/product/edit/${productId}`, {
            method: 'PUT',
            headers: {
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
              'Content-Type': 'application/json'
            },
            body: JSON.stringify(editProductfrom.value)
          });

          if (!response.ok) {
            throw new Error('Network response was not ok.');
          }

          const data = await response.json();
          editProductfrom.value = { 
            productName: data.productName,
            description: data.description,
            price: data.price,
            quantity: data.quantity,
          };
          ElMessage.success('商品信息修改成功');
          getMyProduct(currentPageMy.value, pageSizeMy.value);
          fetchProducts(currentPage.value, pageSize.value);
          editDialogVisible.value = false;
