          return;
        }

        try {
          const response = await fetch(`http://localhost:8080/api/shoppingCart/get/${username}?page=${page}&size=${size}`, {
            method: 'GET',
            headers: {
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
            },
          });

          if (!response.ok) {
            throw new Error('Network response was not ok.');
          }
          const data = await response.json();
