      const handleCurrentChangeCart = newPage => {
        currentPageCart.value = newPage;
        getCartItems(newPage, pageSizeCart.value);
      };
      
      // 支付购物车商品信息
      const payCartItems = async (cartId) => {
        addOrderItem(cartId);
        try {
          const response = await fetch(`http://localhost:8080/api/shoppingCart/pay/${cartId}`, {
            method: 'DELETE',
            headers: {
              'Authorization': 'Bearer ' + localStorage.getItem('token'),
            },
          });

          if (!response.ok) {
            throw new Error('Network response was not ok.');
