<template>
  <div class="CarouselSlider">
    <div class="carousel-inner">
      <div
        v-for="(image, index) in images"
        :key="index"
        class="carousel-item"
        :class="{ active: index === currentIndex }"
      >
        <img :src="image.src" :alt="image.alt" class="carousel-image" />
      </div>
    </div>
    <div class="carousel-indicators">
      <span
        v-for="(image, index) in images"
        :key="index"
        class="indicator-dot"
        :class="{ active: index === currentIndex }"
        @click="goToIndex(index)"
      ></span>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      currentIndex: 0,
      images: [
        { src: require('../assets/image1.jpg'), alt: 'Image 1' },
        { src: require('../assets/image2.jpg'), alt: 'Image 2' },
        { src: require('../assets/image3.jpg'), alt: 'Image 3' },
        { src: require('../assets/image4.jpg'), alt: 'Image 4' },
        // ...其他图片
      ],
      autoPlayTimer: null,
    };
  },
  mounted() {
    this.startAutoPlay();
  },
  beforeUnmount() {
    this.stopAutoPlay();
  },
  methods: {
    goToIndex(index) {
      this.currentIndex = index;
    },
    startAutoPlay() {
      this.autoPlayTimer = setInterval(this.nextImage, 3000); // 切换间隔设置为3秒
    },
    stopAutoPlay() {
      clearInterval(this.autoPlayTimer);
    },
    nextImage() {
      this.currentIndex = (this.currentIndex + 1) % this.images.length;
    },
  },
};
</script>

<style>
.CarouselSlider {
  position: relative;
  overflow: hidden;
}

.carousel-inner {
  position: relative;
  display: flex;
}

.carousel-item {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%; /* 设置轮播项的宽度为100% */
  height: 100%; /* 设置轮播项的高度为100% */
  transition: opacity 0.5s ease-in-out;
  opacity: 0;
  display: flex; /* 使用flex布局来居中图片 */
  justify-content: center; /* 水平居中 */
  align-items: center; /* 垂直居中 */
}

.carousel-item.active {
  opacity: 1;
  position: relative; /* 确保活跃的图片在最上层 */
}

.carousel-image {
  max-width: 100%; /* 图片最大宽度为100% */
  max-height: 100%; /* 图片最大高度为100% */
  object-fit: cover; /* 保持宽高比的同时填充容器 */
}

.carousel-indicators {
  position: absolute;
  bottom: 10px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
}

.indicator-dot {
  width: 10px;
  height: 10px;
  background-color: rgba(175, 174, 174, 0.5);
  border-radius: 50%;
  margin: 0 5px;
  cursor: pointer;
}

.indicator-dot.active {
  background-color: rgba(1, 1, 1, 0.59);
}
</style>
